import{c as t}from"./app.8935f5f1.js";const e={},n=t('<h2 id="resttemplate" tabindex="-1"><a class="header-anchor" href="#resttemplate" aria-hidden="true">#</a> RestTemplate</h2><h3 id="依赖注入" tabindex="-1"><a class="header-anchor" href="#依赖注入" aria-hidden="true">#</a> 依赖注入</h3><div class="language-text ext-text"><pre class="language-text"><code>\t@Bean\n\t// 开启负载均衡\n\t@LoadBalanced\n\tRestTemplate restTemplate() {\n\t\treturn new RestTemplate();\n\t}\n</code></pre></div><p>接下来便可以使用资源地址调用服务</p><div class="language-text ext-text"><pre class="language-text"><code>String url =&quot;http://provider/getHi&quot;;\nString respStr = restTemplate.getForObject(url, String.class);\n\t\t\n</code></pre></div><h3 id="get-请求处理" tabindex="-1"><a class="header-anchor" href="#get-请求处理" aria-hidden="true">#</a> get 请求处理</h3><h4 id="getforentity" tabindex="-1"><a class="header-anchor" href="#getforentity" aria-hidden="true">#</a> getForEntity</h4><p>getForEntity方法的返回值是一个ResponseEntity，ResponseEntity是Spring对HTTP请求响应的封装，包括了几个重要的元素，如响应码、contentType、contentLength、响应消息体等。</p><div class="language-text ext-text"><pre class="language-text"><code>&lt;200,Hi,[Content-Type:&quot;text/plain;charset=UTF-8&quot;, Content-Length:&quot;8&quot;, Date:&quot;Fri, 10 Apr 2020 09:58:44 GMT&quot;, Keep-Alive:&quot;timeout=60&quot;, Connection:&quot;keep-alive&quot;]&gt;\n</code></pre></div><h4 id="返回一个map" tabindex="-1"><a class="header-anchor" href="#返回一个map" aria-hidden="true">#</a> 返回一个Map</h4><p><strong>调用方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t\tString url =&quot;http://provider/getMap&quot;;\n\t\t   \n\t\tResponseEntity&lt;Map&gt; entity = restTemplate.getForEntity(url, Map.class);\n\t\t   \n\t\tSystem.out.println(&quot;respStr: &quot;  + entity.getBody() );\n</code></pre></div><p><strong>生产方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t@GetMapping(&quot;/getMap&quot;)\n\tpublic Map&lt;String, String&gt; getMap() {\n\t\t\n\t\tHashMap&lt;String, String&gt; map = new HashMap&lt;&gt;();\n\t\tmap.put(&quot;name&quot;, &quot;500&quot;);\n\t\treturn map; \n\t}\n</code></pre></div><h4 id="返回对象" tabindex="-1"><a class="header-anchor" href="#返回对象" aria-hidden="true">#</a> 返回对象</h4><p><strong>调用方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t\tResponseEntity&lt;Person&gt; entity = restTemplate.getForEntity(url, Person.class);\n\t\t   \n\t\tSystem.out.println(&quot;respStr: &quot;  + ToStringBuilder.reflectionToString(entity.getBody() ));\n</code></pre></div><p><strong>生产方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t@GetMapping(&quot;/getObj&quot;)\n\tpublic Person getObj() {\n\n\n\t\tPerson person = new Person();\n\t\tperson.setId(100);\n\t\tperson.setName(&quot;xiaoming&quot;);\n\t\treturn person; \n\t}\n</code></pre></div><p><strong>Person类</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\tprivate int id;\n\tprivate String name;\n</code></pre></div><h4 id="传参调用" tabindex="-1"><a class="header-anchor" href="#传参调用" aria-hidden="true">#</a> 传参调用</h4><p><strong>使用占位符</strong></p><pre><code>\tString url =&quot;http://provider/getObjParam?name={1}&quot;;\n\t   \n\tResponseEntity&lt;Person&gt; entity = restTemplate.getForEntity(url, Person.class,&quot;hehehe...&quot;);\n</code></pre><p><strong>使用map</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t\tString url =&quot;http://provider/getObjParam?name={name}&quot;;\n\t\t   \n\t\tMap&lt;String, String&gt; map = Collections.singletonMap(&quot;name&quot;, &quot; memeda&quot;);\n\t\tResponseEntity&lt;Person&gt; entity = restTemplate.getForEntity(url, Person.class,map);\n</code></pre></div><h4 id="返回对象-1" tabindex="-1"><a class="header-anchor" href="#返回对象-1" aria-hidden="true">#</a> 返回对象</h4><div class="language-text ext-text"><pre class="language-text"><code>Person person = restTemplate.getForObject(url, Person.class,map);\n</code></pre></div><h3 id="post-请求处理" tabindex="-1"><a class="header-anchor" href="#post-请求处理" aria-hidden="true">#</a> post 请求处理</h3><p><strong>调用方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t\n\t\tString url =&quot;http://provider/postParam&quot;;\n\t\t   \n\t\tMap&lt;String, String&gt; map = Collections.singletonMap(&quot;name&quot;, &quot; memeda&quot;);\n\t\t ResponseEntity&lt;Person&gt; entity = restTemplate.postForEntity(url, map, Person.class);\n</code></pre></div><p><strong>生产方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t@PostMapping(&quot;/postParam&quot;)\n\tpublic Person postParam(@RequestBody String name) {\n\n\t\tSystem.out.println(&quot;name:&quot; + name);\n\n\t\tPerson person = new Person();\n\t\tperson.setId(100);\n\t\tperson.setName(&quot;xiaoming&quot; + name);\n\t\treturn person; \n\t}\n</code></pre></div><h3 id="postforlocation" tabindex="-1"><a class="header-anchor" href="#postforlocation" aria-hidden="true">#</a> postForLocation</h3><p><strong>调用方</strong></p><div class="language-text ext-text"><pre class="language-text"><code>\t\tString url =&quot;http://provider/postParam&quot;;\n\t\t   \n\t\tMap&lt;String, String&gt; map = Collections.singletonMap(&quot;name&quot;, &quot; memeda&quot;);\n\t\tURI location = restTemplate.postForLocation(url, map, Person.class);\n\t\t\n\t\tSystem.out.println(location);\n</code></pre></div><p><strong>生产方</strong></p><p>需要设置头信息，不然返回的是null</p><div class="language-text ext-text"><pre class="language-text"><code>\tpublic URI postParam(@RequestBody Person person,HttpServletResponse response) throws Exception {\n\n\tURI uri = new URI(&quot;https://www.baidu.com/s?wd=&quot;+person.getName());\n\tresponse.addHeader(&quot;Location&quot;, uri.toString());\n</code></pre></div><h3 id="exchange" tabindex="-1"><a class="header-anchor" href="#exchange" aria-hidden="true">#</a> exchange</h3><p>可以自定义http请求的头信息，同时保护get和post方法</p><h3 id="拦截器" tabindex="-1"><a class="header-anchor" href="#拦截器" aria-hidden="true">#</a> 拦截器</h3><p>需要实现<code>ClientHttpRequestInterceptor</code>接口</p><p><strong>拦截器</strong></p><div class="language-text ext-text"><pre class="language-text"><code>public class LoggingClientHttpRequestInterceptor implements ClientHttpRequestInterceptor {\n\n\t@Override\n\tpublic ClientHttpResponse intercept(HttpRequest request, byte[] body, ClientHttpRequestExecution execution)\n\t\t\tthrows IOException {\n\n\t\tSystem.out.println(&quot;拦截啦！！！&quot;);\n\t\tSystem.out.println(request.getURI());\n\n\t\tClientHttpResponse response = execution.execute(request, body);\n\n\t\tSystem.out.println(response.getHeaders());\n\t\treturn response;\n\t}\n</code></pre></div><p>添加到resttemplate中</p><div class="language-text ext-text"><pre class="language-text"><code>\t@Bean\n\t@LoadBalanced\n\tRestTemplate restTemplate() {\n\t\tRestTemplate restTemplate = new RestTemplate();\n\t\trestTemplate.getInterceptors().add(new LoggingClientHttpRequestInterceptor());\n\t\treturn restTemplate;\n\t}\n</code></pre></div>',47);e.render=function(t,e){return n};export{e as default};
